#!/usr/bin/env bash
# 50.sh — 单次会谈的结构（开场 → 工作 → 收尾，一次 50 分钟会谈怎么走） SOP walkthrough for 心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大)"
WORKFLOW="单次会谈的结构（开场 → 工作 → 收尾，一次 50 分钟会谈怎么走）"

usage() {
  cat <<EOF
50.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./50.sh             # interactive
  ./50.sh --dry-run
  ./50.sh --json
  ./50.sh --explain
  ./50.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "单次会谈的结构（开场 → 工作 → 收尾，一次 50 分钟会谈怎么走）" 工作流。

一句话: 把一次 ~50 分钟的「治疗小时」（therapeutic hour）从「来访者坐下」走到「带着可带走的东西离开 + 治疗师完成记录」，让单次会谈既有结构又留得住治疗关系。

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 治疗关系 / 共同要素 > 单一技术: 这一行的资深人默认「治疗关系的质量、共情、期望、来访者因素」这些**跨流派共有的共同要素**对疗效的解释力,可能不亚于任一流派的特定技术 —— 所以「学对了流派」从来不够,「谁来做、和来访者建立了什么
  • 症状是有功能 / 是适应,不是单纯的「病」: 这一行的人看一个症状,默认先问「它在为这个人 / 这个系统**做什么**」—— 症状常是某个困境下能找到的最优解、是适应而非缺陷,去病理化地理解它,比急着「消除」它更接近治疗。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**开场 / 签到（check-in，~5 min）**：问候、确认本次时长与设置、扫一眼来访者状态；如用结果监测，开场施测 ORS（结果评定量表）。**输入**=上次记录 + 来访者当下呈现；**输出**=本次大致状态基线。"
  "**设置本次焦点（agenda / 焦点协商，~5 min）**：和来访者一起确认「今天工作什么」——可以是来访者带来的事，也可以是上次的延续。CBT 取向会显性列 agenda；动力学 / 人本取向更松，但治疗师心里仍有焦点。"
  "**工作期（working phase，~30–35 min）**：用所属流派的技术做核心工作——CBT 的思维记录 / 行为实验、动力学的此时此地探索 / 移情工作、人本的情感反映、创伤取向的稳定化或加工。全程**监测治疗联盟**与来访者的情绪窗口。"
  "**收尾 / 着陆（closing，~5–8 min）**：把情绪强度降下来（尤其触及创伤 / 强情绪时不能让来访者「带着炸开的状态」离开）、小结今天、确认带走的东西（可能含家庭作业 / 练习）、必要时给反馈量表 SRS（会谈评定量表）。"
  "**会谈后记录（progress note，会谈后 ~5–10 min）**：写当次进展记录——主诉、干预、反应、风险状态、下次计划。这是**伦理与法律要求的最小动作，不是可选项**。"
)
declare -a FAILURE_MODES=(
  "**「流水账会谈」**：每次都从「这周发生了什么」开始且不收口——触发原因是跳过焦点设置（step 2）。避免：哪怕不显性列 agenda，治疗师心里要在前 5 分钟锁定一个焦点。"
  "**「带着炸开的情绪送走来访者」**：工作期触及创伤 / 强情绪后没留够收尾时间——触发原因是工作期超时、收尾被压缩到 2 分钟。避免：把收尾当硬约束，提前 10 分钟开始降强度，宁可工作期短一点。"
  "**「会谈完不记录、攒到周末补」**：记录滞后导致内容失真、风险状态漏记——触发原因是把记录当行政负担。避免：把记录当会谈的一部分，会谈后立刻写。"
  "**「只记内容不记过程 / 反移情」**：新手记录只有「来访者说了什么」，没有「关系里发生了什么、我有什么反应」——后果是督导无料、自我成长停滞。避免：每次记录额外留一行过程 / 反移情观察。"
  "**CLI 化暗示**：这些失败会被抽进会谈结构自检 checklist——「本次是否锁定了一个焦点？」「收尾是否留了 ≥5 分钟且来访者状态已着陆？」「记录是否在 24 小时内完成且含风险状态 + 一行过程观察？」每项 yes/no。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "50-walkthrough"
fi
